-- Add email template for direct workspace invitations (admin-initiated)
INSERT OR IGNORE INTO email_templates (id, slug, name, subject, body_html, body_text, variables, category, enabled, created_at, updated_at) VALUES
  ('et_workspace_invitation', 'workspace-invitation', 'Workspace Invitation', 'You''ve been invited to join {{workspaceName}} on Complerer',
   '<div style="font-family: Red Hat Display, sans-serif; max-width: 480px; margin: 0 auto; padding: 40px 20px; background: #09090b;"><div style="text-align: center; margin-bottom: 32px;"><img src="{{logoUrl}}" alt="Complerer" height="32" /></div><h2 style="color: #fafafa; font-size: 20px; margin-bottom: 8px;">You''ve been invited</h2><p style="color: #a1a1aa; font-size: 14px; line-height: 1.6;">You''ve been invited to join <strong style="color: #fafafa;">{{workspaceName}}</strong> on Complerer as a <strong style="color: #fafafa;">{{role}}</strong>.</p><p style="color: #a1a1aa; font-size: 14px; line-height: 1.6;">Sign in with this email address to accept and access your workspace.</p><div style="text-align: center; margin: 32px 0;"><a href="{{loginUrl}}" style="display: inline-block; background: #34d399; color: #09090b; font-weight: 600; padding: 12px 32px; border-radius: 12px; text-decoration: none; font-size: 14px;">Accept Invitation</a></div><p style="color: #52525b; font-size: 12px; text-align: center;">This invitation expires in 7 days. If you did not expect this invitation, you can ignore this email.</p></div>',
   'You have been invited to join {{workspaceName}} on Complerer as a {{role}}. Sign in at {{loginUrl}} to accept.',
   '["workspaceName", "role", "loginUrl", "logoUrl"]', 'auth', 1, datetime('now'), datetime('now'));
